const { SQSClient, MessageAttribute } = require('@aws-sdk/client-sqs');
const { DynamoDBClient, PutItemCommand } = require('@aws-sdk/client-dynamodb');

// Initialize AWS services
const sqsClient = new SQSClient({ region: 'your-region' });
const dynamoDbClient = new DynamoDBClient({ region: 'your-region' });

// Define database table name and primary key
const tableName = 'financial-transactions';
const primaryKey = 'transactionId';

// Process messages from SQS queue
async function processMessages() {
  const params = {
    QueueUrl: 'https://sqs.your-region.amazonaws.com/your-account-id/your-queue-name',
    MaxNumberOfMessages: 10,
  };

  try {
    // Receive messages from SQS
    const data = await sqsClient.receiveMessage(params);
    if (data.Messages) {
      for (const message of data.Messages) {
        // Parse message content
        const transactionId = message.MessageAttributes.transactionId.Value;
        const amount = message.MessageAttributes.amount.Value;

        // Execute database update directly based on message content
        const params = {
          TableName: tableName,
          Item: {
            [primaryKey]: transactionId,
            amount,
          },
        };

        await dynamoDbClient.send(new PutItemCommand(params));

        // Delete processed message from SQS
        const deleteParams = {
          QueueUrl: 'https://sqs.your-region.amazonaws.com/your-account-id/your-queue-name',
          ReceiptHandle: message.ReceiptHandle,
        };
        await sqsClient.deleteMessage(deleteParams);
      }
    }
  } catch (err) {
    console.error(err);
  }
}

// Run the processMessages function
processMessages();